"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import {
  Calendar,
  Loader2,
  ArrowLeft,
  CheckCircle2,
  XCircle,
  Clock,
  User,
  Phone,
  Video,
  FileText,
  AlertCircle,
  ClipboardList,
} from "lucide-react";

interface Appointment {
  id: string;
  type: string;
  status: string;
  reason: string | null;
  fee: number | null;
  notes: string | null;
  doctor: { name: string; specialization: string };
  patient: { name: string; phone: string | null };
  slot: { date: string; startTime: string; endTime: string };
}

export default function HospitalAppointmentsManagerPage() {
  const router = useRouter();
  const { user, isLoading } = useAuth();

  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [loading, setLoading] = useState(true);
  
  // Prescription / Notes modal
  const [selectedApp, setSelectedApp] = useState<Appointment | null>(null);
  const [notes, setNotes] = useState("");
  const [completing, setCompleting] = useState(false);
  const [updatingId, setUpdatingId] = useState<string | null>(null);

  const fetchAppointments = async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/appointments");
      const data = await res.json();
      if (data.success) {
        setAppointments(data.data.appointments);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!isLoading) {
      if (!user || user.role !== "HOSPITAL") {
        router.push("/login");
        return;
      }
      fetchAppointments();
    }
  }, [user, isLoading, router]);

  const handleConfirm = async (id: string) => {
    setUpdatingId(id);
    try {
      const res = await fetch("/api/appointments", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ appointmentId: id, status: "CONFIRMED" }),
      });
      const data = await res.json();
      if (data.success) {
        fetchAppointments();
      }
    } catch (err) {
      console.error(err);
    } finally {
      setUpdatingId(null);
    }
  };

  const handleCancel = async (id: string) => {
    if (!confirm("Are you sure you want to cancel this appointment?")) return;
    setUpdatingId(id);
    try {
      const res = await fetch("/api/appointments", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ appointmentId: id, status: "CANCELLED" }),
      });
      const data = await res.json();
      if (data.success) {
        fetchAppointments();
      }
    } catch (err) {
      console.error(err);
    } finally {
      setUpdatingId(null);
    }
  };

  const openCompleteModal = (app: Appointment) => {
    setSelectedApp(app);
    setNotes(app.notes || "");
  };

  const handleCompleteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedApp) return;

    setCompleting(true);
    try {
      const res = await fetch("/api/appointments", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          appointmentId: selectedApp.id,
          status: "COMPLETED",
          notes: notes.trim(),
        }),
      });
      const data = await res.json();
      if (data.success) {
        setSelectedApp(null);
        fetchAppointments();
      }
    } catch (err) {
      console.error(err);
    } finally {
      setCompleting(false);
    }
  };

  if (isLoading || loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-surface-secondary">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="w-10 h-10 text-primary-600 animate-spin" />
          <p className="text-text-secondary text-sm">Retrieving clinic reservations...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-surface-secondary pb-12">
      {/* Header */}
      <header className="bg-white border-b border-border sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button
              onClick={() => router.push("/dashboard")}
              className="text-text-muted hover:text-text-primary p-2 -ml-2 rounded-lg hover:bg-surface-secondary transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <span className="text-lg font-bold text-text-primary">Appointments Manager</span>
          </div>
          <span className="text-xs text-text-muted">Clinical Reception</span>
        </div>
      </header>

      {/* Main Container */}
      <main className="max-w-6xl mx-auto px-4 py-8">
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-text-primary">Patient Consultations</h1>
          <p className="text-sm text-text-secondary mt-1">
            Manage reservation schedules, approve bookings, and upload prescriptions.
          </p>
        </div>

        {appointments.length === 0 ? (
          <div className="bg-white border border-border rounded-2xl py-16 px-4 text-center">
            <ClipboardList className="w-12 h-12 text-text-muted mx-auto mb-4 opacity-50" />
            <h3 className="text-lg font-bold text-text-primary mb-1">No Reservations Found</h3>
            <p className="text-sm text-text-secondary max-w-sm mx-auto">
              Any patient bookings scheduled at your facility will be listed here.
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            {appointments.map((app) => {
              const isUpdating = updatingId === app.id;
              const dateFormatted = new Date(app.slot.date).toLocaleDateString("en-IN", {
                weekday: "short",
                month: "short",
                day: "numeric",
              });

              return (
                <div
                  key={app.id}
                  className="bg-white border border-border rounded-2xl p-5 flex flex-col md:flex-row md:items-center justify-between gap-6 hover-lift"
                >
                  {/* Left: Patient & Doctor Info */}
                  <div className="space-y-3 md:w-2/5">
                    <div className="flex items-center gap-2">
                      <span className="text-sm font-extrabold text-text-primary">{app.patient.name}</span>
                      <span
                        className={`text-[9px] px-2 py-0.5 rounded-md font-bold uppercase ${
                          app.type === "VIDEO_CALL"
                            ? "bg-primary-50 text-primary-700 border border-primary-200"
                            : "bg-surface-secondary text-text-muted border border-border"
                        }`}
                      >
                        {app.type === "VIDEO_CALL" ? "Online Video" : "In-Person"}
                      </span>
                    </div>

                    <div className="text-xs text-text-secondary space-y-1">
                      <p className="flex items-center gap-1.5">
                        <User className="w-3.5 h-3.5 text-text-muted" /> Doctor: <strong>{app.doctor.name} ({app.doctor.specialization})</strong>
                      </p>
                      {app.patient.phone && (
                        <p className="flex items-center gap-1.5">
                          <Phone className="w-3.5 h-3.5 text-text-muted" /> Phone: <span>{app.patient.phone}</span>
                        </p>
                      )}
                      {app.reason && (
                        <p className="text-text-muted italic mt-1 font-medium">
                          " {app.reason} "
                        </p>
                      )}
                    </div>
                  </div>

                  {/* Middle: Timing & Fees */}
                  <div className="flex flex-row md:flex-col justify-between md:justify-center gap-4 text-xs md:w-1/4">
                    <div>
                      <span className="text-text-muted block">Slot Time</span>
                      <span className="font-bold text-text-primary mt-0.5 block">
                        {dateFormatted} @ {app.slot.startTime}
                      </span>
                    </div>
                    <div>
                      <span className="text-text-muted block">Consultation Fee</span>
                      <span className="font-extrabold text-text-primary mt-0.5 block">
                        ₹{app.fee || 0}
                      </span>
                    </div>
                  </div>

                  {/* Right: Status & Actions */}
                  <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3.5 justify-end md:w-1/3 pt-4 md:pt-0 border-t md:border-t-0 border-border">
                    <span
                      className={`text-xs px-2.5 py-1 rounded-lg font-bold uppercase tracking-wider ${
                        app.status === "CONFIRMED"
                          ? "bg-emerald-50 text-emerald-700 border border-emerald-200"
                          : app.status === "PENDING"
                          ? "bg-amber-50 text-amber-700 border border-amber-200"
                          : app.status === "COMPLETED"
                          ? "bg-blue-50 text-blue-700 border border-blue-200"
                          : "bg-surface-secondary text-text-muted border border-border"
                      }`}
                    >
                      {app.status}
                    </span>

                    <div className="flex gap-2 w-full sm:w-auto">
                      {app.status === "PENDING" && (
                        <>
                          <button
                            disabled={isUpdating}
                            onClick={() => handleConfirm(app.id)}
                            className="flex-1 sm:flex-initial px-3 py-1.5 bg-emerald-600 hover:bg-emerald-700 text-white font-bold text-xs rounded-xl shadow-xs transition-colors cursor-pointer flex items-center justify-center gap-1"
                          >
                            {isUpdating ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <CheckCircle2 className="w-3.5 h-3.5" />} Approve
                          </button>
                          <button
                            disabled={isUpdating}
                            onClick={() => handleCancel(app.id)}
                            className="flex-1 sm:flex-initial px-3 py-1.5 bg-red-50 hover:bg-red-100 text-error font-bold text-xs rounded-xl border border-red-200 transition-colors cursor-pointer flex items-center justify-center gap-1"
                          >
                            <XCircle className="w-3.5 h-3.5" /> Reject
                          </button>
                        </>
                      )}

                      {app.status === "CONFIRMED" && (
                        <>
                          {app.type === "VIDEO_CALL" && (
                            <button
                              onClick={() => router.push(`/consultations/${app.id}`)}
                              className="flex-1 sm:flex-initial px-3 py-1.5 bg-emerald-600 hover:bg-emerald-700 text-white font-bold text-xs rounded-xl shadow-xs transition-colors cursor-pointer flex items-center justify-center gap-1"
                            >
                              <Video className="w-3.5 h-3.5" /> Start Consult
                            </button>
                          )}
                          <button
                            onClick={() => openCompleteModal(app)}
                            className="flex-1 sm:flex-initial px-3 py-1.5 bg-primary-600 hover:bg-primary-700 text-white font-bold text-xs rounded-xl shadow-xs transition-colors cursor-pointer flex items-center justify-center gap-1"
                          >
                            <CheckCircle2 className="w-3.5 h-3.5" /> Complete
                          </button>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </main>

      {/* Complete Booking & Add Prescription Notes Modal */}
      {selectedApp && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-xs flex items-center justify-center p-4 z-50 animate-fade-in">
          <div className="bg-white border border-border rounded-2xl w-full max-w-md shadow-xl overflow-hidden">
            <div className="p-5 border-b border-border bg-surface-secondary/20 flex justify-between items-center">
              <h3 className="font-bold text-text-primary text-base">Complete Consultation Session</h3>
              <button
                onClick={() => setSelectedApp(null)}
                className="text-text-muted hover:text-text-primary text-xl font-bold cursor-pointer"
              >
                &times;
              </button>
            </div>

            <form onSubmit={handleCompleteSubmit} className="p-5 space-y-4">
              <div className="space-y-1.5">
                <label className="text-xs font-bold text-text-primary uppercase tracking-wider flex items-center gap-1">
                  <FileText className="w-4 h-4 text-text-muted" /> Prescription Notes / Diagnosis
                </label>
                <textarea
                  rows={4}
                  required
                  placeholder="Enter medical diagnosis, prescription dosage details, advice, and post-care follow-up instructions..."
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  className="w-full text-sm border border-border rounded-xl px-3.5 py-2.5 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                />
              </div>

              <div className="pt-4 border-t border-border flex justify-end gap-3">
                <button
                  type="button"
                  onClick={() => setSelectedApp(null)}
                  className="px-4 py-2 border border-border text-text-secondary font-semibold text-xs rounded-xl hover:bg-surface-secondary transition-colors cursor-pointer"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={completing}
                  className="px-4 py-2 bg-emerald-600 hover:bg-emerald-700 text-white font-bold text-xs rounded-xl shadow-xs transition-colors flex items-center gap-1 cursor-pointer disabled:opacity-50"
                >
                  {completing ? (
                    <>
                      <Loader2 className="w-3.5 h-3.5 animate-spin" /> Saving...
                    </>
                  ) : (
                    "Save & Complete Session"
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
